const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;

const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
  const basePremium = calculateBasePremium(step.items);
  const itemSurcharges = sumItemSpecificSurcharges(step.items);
  const premium = Math.ceil(
    basePremium +
      itemSurcharges +
      firstContractSurcharge(basePremium) -
      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) +
      PROCESSING_FEE,
  );
  return { premium };
};
